proof:
by_cases hf : ContinuousOn f (Set.Icc ( -1 ) 1);
· have h_subst : ∫ x in (0 : ℝ)..Real.pi, Real.sin x * f (Real.cos x) = ∫ u in (Real.cos 0)..Real.cos Real.pi, f u * (-1) := by
    convert intervalIntegral.integral_comp_mul_deriv' _ _ _ using 2 <;> norm_num;
    rotate_left;
    exacts [ fun x => -Real.sin x, fun x hx => by simpa using Real.hasDerivAt_cos x, Continuous.continuousOn <| by continuity, ContinuousOn.neg <| hf.mono <| by intro u hu; rcases hu with ⟨ x, hx, rfl ⟩ ; exact ⟨ Real.neg_one_le_cos _, Real.cos_le_one _ ⟩, funext fun x => by ring ];
  norm_num [ h_subst ];
  rw [ ← intervalIntegral.integral_symm ];
· by_contra h;
  -- Since $f$ is not continuous on $[-1, 1]$, the integral $\int_{-1}^{1} f(y) \, dy$ does not exist.
  have h_int_nonexist : ¬(MeasureTheory.IntegrableOn f (Set.Icc (-1 : ℝ) 1)) := by
    intro H;
    refine' h _;
    have h_subst : ∫ x in (0 : ℝ)..Real.pi, Real.sin x * f (Real.cos x) = ∫ y in (Set.image Real.cos (Set.Icc 0 Real.pi)), f y := by
      rw [ MeasureTheory.integral_image_eq_integral_abs_deriv_smul ] <;> norm_num [ Real.pi_pos.le ];
      any_goals intro x hx₁ hx₂; exact Real.hasDerivAt_cos x |> HasDerivAt.hasDerivWithinAt;
      · rw [ MeasureTheory.integral_Icc_eq_integral_Ioc, intervalIntegral.integral_of_le Real.pi_pos.le ] ; norm_num [ abs_neg, abs_of_nonneg, Real.sin_nonneg_of_nonneg_of_le_pi ];
        exact MeasureTheory.setIntegral_congr_fun measurableSet_Ioc fun x hx => by rw [ abs_of_nonneg ( Real.sin_nonneg_of_nonneg_of_le_pi hx.1.le hx.2 ) ] ;
      · exact Real.injOn_cos.mono <| Set.Icc_subset_Icc_left <| by linarith [ Real.pi_pos ];
    rw [ h_subst, show Real.cos '' Set.Icc 0 Real.pi = Set.Icc ( -1 ) 1 from ?_ ];
    · rw [ MeasureTheory.integral_Icc_eq_integral_Ioc, intervalIntegral.integral_of_le ] ; norm_num;
    · ext x
      simp [Set.mem_image];
      exact ⟨ fun ⟨ y, hy, hy' ⟩ => ⟨ hy'.symm ▸ Real.neg_one_le_cos _, hy'.symm ▸ Real.cos_le_one _ ⟩, fun hx => ⟨ Real.arccos x, ⟨ Real.arccos_nonneg _, Real.arccos_le_pi _ ⟩, by rw [ Real.cos_arccos hx.1 hx.2 ] ⟩ ⟩;
  rw [ intervalIntegral.integral_undef ] at h;
  · rw [ intervalIntegral.integral_undef ] at h <;> norm_num at *;
    rw [ intervalIntegrable_iff_integrableOn_Icc_of_le ] <;> norm_num [ h_int_nonexist ];
  · rw [ intervalIntegrable_iff_integrableOn_Ioo_of_le Real.pi_pos.le ];
    intro H;
    have h_integrable : MeasureTheory.IntegrableOn (fun y => f y) (Set.image Real.cos (Set.Ioo 0 Real.pi)) := by
      rw [ MeasureTheory.integrableOn_image_iff_integrableOn_abs_deriv_smul ];
      any_goals intro x hx; exact Real.hasDerivAt_cos x |> HasDerivAt.hasDerivWithinAt;
      · simp_all +decide [ abs_mul, mul_comm ];
        exact H.congr_fun ( fun x hx => by rw [ abs_of_nonneg ( Real.sin_nonneg_of_nonneg_of_le_pi hx.1.le hx.2.le ) ] ) measurableSet_Ioo;
      · exact measurableSet_Ioo;
      · exact fun x hx y hy hxy => Real.injOn_cos ⟨ by linarith [ Real.pi_pos, hx.1 ], by linarith [ Real.pi_pos, hx.2 ] ⟩ ⟨ by linarith [ Real.pi_pos, hy.1 ], by linarith [ Real.pi_pos, hy.2 ] ⟩ hxy;
    have h_integrable : MeasureTheory.IntegrableOn (fun y => f y) (Set.Ioo (-1 : ℝ) 1) := by
      refine' h_integrable.mono_set _;
      exact fun x hx => ⟨ Real.arccos x, ⟨ Real.arccos_pos.2 hx.2, lt_of_le_of_ne ( Real.arccos_le_pi _ ) ( by aesop ) ⟩, by rw [ Real.cos_arccos hx.1.le hx.2.le ] ⟩;
    exact h_int_nonexist <| by simpa only [ MeasureTheory.IntegrableOn, MeasureTheory.Measure.restrict_congr_set MeasureTheory.Ioo_ae_eq_Icc ] using h_integrable;

